const UnitConverter = () => {
  const [category, setCategory] = React.useState('length');
  const [from, setFrom] = React.useState('m');
  const [to, setTo] = React.useState('ft');
  const [value, setValue] = React.useState(1);
  const [result, setResult] = React.useState('');

  const units = {
    length: {
      m: 1, km: 1000, cm: 0.01, mm: 0.001, mi: 1609.34, yd: 0.9144, ft: 0.3048, in: 0.0254
    },
    weight: {
      kg: 1, g: 0.001, mg: 0.000001, lb: 0.453592, oz: 0.0283495, st: 6.35029
    },
    temperature: {
      C: 'C', F: 'F', K: 'K'
    },
    volume: {
      l: 1, ml: 0.001, gal: 3.78541, qt: 0.946353, pt: 0.473176, cup: 0.236588, floz: 0.0295735
    }
  };

  const unitLabels = {
    length: { m: 'Meters', km: 'Kilometers', cm: 'Centimeters', mm: 'Millimeters', mi: 'Miles', yd: 'Yards', ft: 'Feet', in: 'Inches' },
    weight: { kg: 'Kilograms', g: 'Grams', mg: 'Milligrams', lb: 'Pounds', oz: 'Ounces', st: 'Stone' },
    temperature: { C: 'Celsius', F: 'Fahrenheit', K: 'Kelvin' },
    volume: { l: 'Liters', ml: 'Milliliters', gal: 'Gallons (US)', qt: 'Quarts', pt: 'Pints', cup: 'Cups', floz: 'Fluid Ounces' }
  };

  React.useEffect(() => {
    const keys = Object.keys(units[category]);
    setFrom(keys[0]);
    setTo(keys[1] || keys[0]);
    setResult('');
  }, [category]);

  const convert = () => {
    const v = Number(value);
    if (isNaN(v)) { setResult('Invalid input'); return; }
    if (category === 'temperature') {
      let celsius;
      if (from === 'C') celsius = v;
      else if (from === 'F') celsius = (v - 32) * 5 / 9;
      else if (from === 'K') celsius = v - 273.15;
      let out;
      if (to === 'C') out = celsius;
      else if (to === 'F') out = celsius * 9 / 5 + 32;
      else if (to === 'K') out = celsius + 273.15;
      setResult(out.toFixed(4).replace(/\.0+$/, '').replace(/(\.\d+?)0+$/, '$1'));
    } else {
      const base = v * units[category][from];
      const out = base / units[category][to];
      setResult(out.toFixed(6).replace(/\.0+$/, '').replace(/(\.\d+?)0+$/, '$1'));
    }
  };

  React.useEffect(() => {
    convert();
  }, [value, from, to, category]);

  return React.createElement('div', { style: { fontFamily: 'system-ui, sans-serif', padding: '16px', display: 'flex', flexDirection: 'column', gap: '14px', height: '100%', overflow: 'auto' } },
    React.createElement('h3', { style: { margin: 0, fontSize: '16px', fontWeight: 600, color: '#111827' } }, 'Unit Converter'),
    React.createElement('div', { style: { display: 'flex', gap: '8px' } },
      ['length', 'weight', 'temperature', 'volume'].map(c => React.createElement('button', {
        key: c,
        onClick: () => setCategory(c),
        style: {
          flex: 1,
          fontSize: '12px',
          padding: '6px',
          borderRadius: '4px',
          border: '1px solid #d1d5db',
          background: category === c ? '#2563eb' : '#fff',
          color: category === c ? '#fff' : '#374151',
          cursor: 'pointer',
          fontWeight: 600,
          textTransform: 'capitalize'
        }
      }, c))
    ),
    React.createElement('div', { style: { background: '#f9fafb', borderRadius: '8px', padding: '12px', display: 'flex', flexDirection: 'column', gap: '10px' } },
      React.createElement('div', null,
        React.createElement('div', { style: { fontSize: '11px', fontWeight: 600, color: '#6b7280', marginBottom: '4px' } }, 'Value'),
        React.createElement('input', { type: 'number', value: value, onChange: e => setValue(e.target.value), style: { width: '100%', fontSize: '14px', padding: '8px', borderRadius: '4px', border: '1px solid #d1d5db', boxSizing: 'border-box' } })
      ),
      React.createElement('div', { style: { display: 'grid', gridTemplateColumns: '1fr auto 1fr', gap: '8px', alignItems: 'end' } },
        React.createElement('div', null,
          React.createElement('div', { style: { fontSize: '11px', fontWeight: 600, color: '#6b7280', marginBottom: '4px' } }, 'From'),
          React.createElement('select', { value: from, onChange: e => setFrom(e.target.value), style: { width: '100%', fontSize: '13px', padding: '8px', borderRadius: '4px', border: '1px solid #d1d5db' } },
            Object.keys(units[category]).map(u => React.createElement('option', { key: u, value: u }, unitLabels[category][u]))
          )
        ),
        React.createElement('div', { style: { fontSize: '18px', color: '#6b7280', paddingBottom: '8px' } }, '↔'),
        React.createElement('div', null,
          React.createElement('div', { style: { fontSize: '11px', fontWeight: 600, color: '#6b7280', marginBottom: '4px' } }, 'To'),
          React.createElement('select', { value: to, onChange: e => setTo(e.target.value), style: { width: '100%', fontSize: '13px', padding: '8px', borderRadius: '4px', border: '1px solid #d1d5db' } },
            Object.keys(units[category]).map(u => React.createElement('option', { key: u, value: u }, unitLabels[category][u]))
          )
        )
      ),
      React.createElement('div', { style: { background: '#eff6ff', borderRadius: '6px', padding: '12px', textAlign: 'center', marginTop: '4px' } },
        React.createElement('div', { style: { fontSize: '11px', color: '#2563eb', fontWeight: 600 } }, 'RESULT'),
        React.createElement('div', { style: { fontSize: '20px', fontWeight: 700, color: '#111827', marginTop: '4px' } }, result, ' ', unitLabels[category][to])
      )
    )
  );
};
render(<UnitConverter/>);
